import anthropic
from pathlib import Path

client = anthropic.Anthropic()

def read_file(path: str) -> str:
    p = Path(path)
    if not p.exists():
        raise FileNotFoundError(f"File not found: {path}")
    return p.read_text()

def dispatch_tool(block) -> dict:
    """Execute one tool_use block and return a tool_result dict."""
    HANDLERS = {"read_file": read_file}
    fn = HANDLERS.get(block.name)

    if fn is None:
        return {
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": f"No handler for tool '{block.name}'",
            "is_error": True,
        }

    try:
        result = fn(**block.input)
        return {
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": str(result),
            "is_error": False,
        }
    except FileNotFoundError as exc:
        # Tool-level error: model can recover (try a different path)
        return {
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": str(exc),
            "is_error": True,
        }
    except PermissionError as exc:
        # Also a tool-level error
        return {
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": f"Permission denied: {exc}",
            "is_error": True,
        }

import time
import random
import anthropic

RETRYABLE_STATUS_CODES = {429, 503, 529}

def create_with_retry(
    client: anthropic.Anthropic,
    max_retries: int = 4,
    base_delay: float = 2.0,
    **kwargs,
):
    """Call client.messages.create with exponential backoff for transient errors."""
    last_exc = None
    for attempt in range(max_retries + 1):
        try:
            return client.messages.create(**kwargs)
        except anthropic.RateLimitError as exc:
            last_exc = exc
            # Respect Retry-After header if present
            retry_after = getattr(exc, "retry_after", None)
            delay = float(retry_after) if retry_after else base_delay * (2 ** attempt)
        except anthropic.APIStatusError as exc:
            if exc.status_code not in RETRYABLE_STATUS_CODES:
                raise  # non-retryable (400, 401, 403) — propagate immediately
            last_exc = exc
            delay = base_delay * (2 ** attempt)
        except (anthropic.APIConnectionError, anthropic.APITimeoutError) as exc:
            last_exc = exc
            delay = base_delay * (2 ** attempt)

        if attempt < max_retries:
            jitter = random.uniform(0, delay * 0.2)
            time.sleep(delay + jitter)

    raise RuntimeError(f"API call failed after {max_retries} retries") from last_exc

from dataclasses import dataclass, field
from typing import Literal

@dataclass
class AgentResult:
    status: Literal["complete", "partial", "constraint_violated", "api_error"]
    output: str
    completed_steps: list[str] = field(default_factory=list)
    remaining_hint: str = ""

def run_agent_safe(
    system: str,
    tools: list,
    dispatch_fn,
    task: str,
    max_turns: int = 20,
) -> AgentResult:
    messages = [{"role": "user", "content": task}]
    completed_steps: list[str] = []

    for turn in range(max_turns):
        try:
            response = create_with_retry(client, model="claude-sonnet-4-6",
                                          max_tokens=4096, system=system,
                                          tools=tools, messages=messages)
        except Exception as exc:
            return AgentResult(
                status="api_error",
                output=str(exc),
                completed_steps=completed_steps,
            )

        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "max_tokens":
            return AgentResult(
                status="partial",
                output="Response truncated — context window exhausted.",
                completed_steps=completed_steps,
                remaining_hint="Trim context and retry from last completed step.",
            )

        if response.stop_reason == "end_turn":
            text = next((b.text for b in reversed(response.content) if b.type == "text"), "")
            return AgentResult(status="complete", output=text, completed_steps=completed_steps)

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            try:
                result = dispatch_fn(block)
            except ConstraintViolation as exc:
                return AgentResult(
                    status="constraint_violated",
                    output=str(exc),
                    completed_steps=completed_steps,
                )
            tool_results.append(result)
            if not result.get("is_error"):
                completed_steps.append(f"{block.name}({block.input})")

        messages.append({"role": "user", "content": tool_results})

    # max_turns exhausted
    return AgentResult(
        status="partial",
        output=f"Did not complete within {max_turns} turns.",
        completed_steps=completed_steps,
        remaining_hint="Increase max_turns or refine the task scope.",
    )

from collections import defaultdict

class ErrorGuard:
    def __init__(self, max_errors_per_tool: int = 3):
        self._counts: dict[str, int] = defaultdict(int)
        self._max = max_errors_per_tool

    def record(self, tool_name: str, is_error: bool) -> None:
        if is_error:
            self._counts[tool_name] += 1
            if self._counts[tool_name] >= self._max:
                raise RuntimeError(
                    f"Tool '{tool_name}' has failed {self._counts[tool_name]} consecutive times. "
                    "Aborting to prevent retry loop."
                )
        else:
            self._counts[tool_name] = 0  # reset on success

# Use in the loop:
guard = ErrorGuard(max_errors_per_tool=3)
for block in response.content:
    if block.type != "tool_use":
        continue
    result = dispatch_fn(block)
    guard.record(block.name, result.get("is_error", False))
    tool_results.append(result)

import logging
from enum import Enum
from dataclasses import dataclass

logger = logging.getLogger(__name__)

class ErrorKind(Enum):
    NOT_FOUND = "not_found"
    PERMISSION = "permission"
    INVALID_INPUT = "invalid_input"
    EXTERNAL = "external"         # HTTP / network
    UNKNOWN = "unknown"

@dataclass
class ToolError:
    kind: ErrorKind
    message: str
    hint: str = ""

    def to_result(self, tool_use_id: str) -> dict:
        content = self.message
        if self.hint:
            content += f" Hint: {self.hint}"
        return {
            "type": "tool_result",
            "tool_use_id": tool_use_id,
            "content": content,
            "is_error": True,
        }

def classify_exception(exc: Exception) -> ToolError:
    if isinstance(exc, FileNotFoundError):
        return ToolError(
            kind=ErrorKind.NOT_FOUND,
            message=str(exc),
            hint="Check the path for typos or try search_code first.",
        )
    if isinstance(exc, PermissionError):
        return ToolError(
            kind=ErrorKind.PERMISSION,
            message=str(exc),
            hint="This path is outside the allowed write zone.",
        )
    if isinstance(exc, ValueError):
        return ToolError(
            kind=ErrorKind.INVALID_INPUT,
            message=str(exc),
        )
    return ToolError(kind=ErrorKind.UNKNOWN, message=str(exc))


def safe_dispatch(block, handlers: dict) -> dict:
    fn = handlers.get(block.name)
    if fn is None:
        return {
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": f"No handler registered for tool '{block.name}'.",
            "is_error": True,
        }
    try:
        output = fn(**block.input)
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": str(output), "is_error": False}
    except ConstraintViolation:
        raise  # let it propagate — never suppress
    except Exception as exc:
        err = classify_exception(exc)
        logger.warning(
            "Tool error",
            extra={"tool": block.name, "kind": err.kind.value, "msg": err.message},
        )
        return err.to_result(block.id)
